import ApiService from "@/api/api";
import { getUserInfo } from "../CustomTaskList/api";

interface IAddParams {
  task_name: string;
  date: string;
  detail_desc: string;
  detail_image_url_list: string[];
  need_upload_image: number;
}

interface IUpdateParams extends IAddParams {
  schedule_id: string;
  task_id: string;
}

interface IDelParams {
  schedule_id: string;
  task_id: string;
}

export const addCustomTask = async (data: IAddParams) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/custom-task/create", {
    ...data,
    stu_tal_id: stu_talid,
    token,
  });
};

export const updateCustomTask = async (data: IUpdateParams) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/custom-task/modify", {
    ...data,
    stu_tal_id: stu_talid,
    token,
  });
};

export const delCustomTask = async (data: IDelParams) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/custom-task/delete", {
    ...data,
    stu_tal_id: stu_talid,
    token,
  });
};

// 自定义作业详情
export const customTaskReport = async (data: IDelParams) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/custom-task/detail", {
    stu_tal_id: stu_talid,
    ...data,
    token,
  });
};
